import React, { useEffect, useRef, useState } from 'react';
import './App.css';

type Todo = {
  id: number;
  text: string;
  done: boolean;
};

type Filter = 'all' | 'active' | 'completed';

type PendingUndo = {
  item: Todo;
  index: number;
};

export default function App() {
  const [newTask, setNewTask] = useState('');
  const [todos, setTodos] = useState<Todo[]>([]);
  const [filter, setFilter] = useState<Filter>('all');
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editDraft, setEditDraft] = useState('');
  const [pendingUndo, setPendingUndo] = useState<PendingUndo | null>(null);
  const [liveMessage, setLiveMessage] = useState('');
  const nextId = useRef(1);
  const undoTimerRef = useRef<number | null>(null);
  const editInputRef = useRef<HTMLInputElement | null>(null);
  const editButtonRefs = useRef(new Map<number, HTMLButtonElement>());
  const returnFocusId = useRef<number | null>(null);

  const clearUndoTimer = () => {
    if (undoTimerRef.current !== null) {
      window.clearTimeout(undoTimerRef.current);
      undoTimerRef.current = null;
    }
  };

  useEffect(() => () => clearUndoTimer(), []);

  useEffect(() => {
    if (editingId !== null) {
      editInputRef.current?.focus();
      editInputRef.current?.select();
      return;
    }
    const taskId = returnFocusId.current;
    if (taskId !== null) {
      returnFocusId.current = null;
      editButtonRefs.current.get(taskId)?.focus();
    }
  }, [editingId]);

  const visibleTodos = todos.filter((todo) => {
    if (filter === 'active') return !todo.done;
    if (filter === 'completed') return todo.done;
    return true;
  });
  const remainingCount = todos.filter((todo) => !todo.done).length;
  const remainingLabel = remainingCount === 1
    ? '1 item left'
    : remainingCount + ' items left';
  const hasCompleted = todos.some((todo) => todo.done);

  const addTask = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const normalizedTask = newTask.trim();
    if (!normalizedTask) return;
    setTodos((current) => [
      ...current,
      { id: nextId.current++, text: normalizedTask, done: false }
    ]);
    setNewTask('');
    setLiveMessage('Added ' + normalizedTask + '.');
  };

  const toggleTask = (taskId: number) => {
    setTodos((current) => current.map((todo) => (
      todo.id === taskId ? { ...todo, done: !todo.done } : todo
    )));
  };

  const startEditing = (todo: Todo) => {
    setEditingId(todo.id);
    setEditDraft(todo.text);
  };

  const finishEditing = (saveChanges: boolean) => {
    if (editingId === null) return;
    const taskId = editingId;
    const normalizedDraft = editDraft.trim();
    if (saveChanges && normalizedDraft) {
      setTodos((current) => current.map((todo) => (
        todo.id === taskId ? { ...todo, text: normalizedDraft } : todo
      )));
      setLiveMessage('Updated task to ' + normalizedDraft + '.');
    }
    returnFocusId.current = taskId;
    setEditingId(null);
    setEditDraft('');
  };

  const onEditKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      finishEditing(true);
    } else if (event.key === 'Escape') {
      event.preventDefault();
      finishEditing(false);
    }
  };

  const removeTask = (taskId: number) => {
    const removedIndex = todos.findIndex((todo) => todo.id === taskId);
    if (removedIndex < 0) return;
    const removedTodo = todos[removedIndex];
    clearUndoTimer();
    setTodos((current) => current.filter((todo) => todo.id !== taskId));
    setPendingUndo({ item: removedTodo, index: removedIndex });
    setLiveMessage('Removed ' + removedTodo.text + '. Undo available for 5 seconds.');
    undoTimerRef.current = window.setTimeout(() => {
      undoTimerRef.current = null;
      setPendingUndo(null);
      setLiveMessage('Undo expired for ' + removedTodo.text + '.');
    }, 5000);
  };

  const undoRemoval = () => {
    if (!pendingUndo) return;
    const snapshot = pendingUndo;
    clearUndoTimer();
    setTodos((current) => {
      if (current.some((todo) => todo.id === snapshot.item.id)) return current;
      const restoredTodos = [...current];
      restoredTodos.splice(
        Math.min(snapshot.index, restoredTodos.length),
        0,
        snapshot.item
      );
      return restoredTodos;
    });
    setPendingUndo(null);
    setLiveMessage('Restored ' + snapshot.item.text + '.');
  };

  const clearCompleted = () => {
    setTodos((current) => current.filter((todo) => !todo.done));
    setLiveMessage('Cleared completed tasks.');
  };

  return (
    <main className="main">
      <section className="section">
        <h1>Pressure Todo List</h1>
        <div className="card">
          <form className="input-row todo-form" aria-label="Add task" onSubmit={addTask}>
            <input
              id="new-task"
              className="input"
              value={newTask}
              onChange={(event) => setNewTask(event.target.value)}
              placeholder="Add a task"
              autoComplete="off"
              aria-label="New todo"
              aria-controls="todo-items"
              aria-describedby="todo-instructions items-left"
            />
            <button type="submit" className="primary" disabled={!newTask.trim()}>
              Add
            </button>
          </form>
          <p id="todo-instructions" className="instructions">
            Press Enter to add. Use Edit to rename a task.
          </p>

          <ul id="todo-items" className="list" aria-label="Todo items">
            {visibleTodos.map((todo) => (
              <li key={todo.id} className="item">
                <div className="item-main">
                  <input
                    className="todo-checkbox"
                    type="checkbox"
                    checked={todo.done}
                    onChange={() => toggleTask(todo.id)}
                    aria-label={'Mark ' + todo.text + (todo.done ? ' active' : ' complete')}
                  />
                  {editingId === todo.id ? (
                    <input
                      ref={editInputRef}
                      className="edit-input"
                      value={editDraft}
                      onChange={(event) => setEditDraft(event.target.value)}
                      onKeyDown={onEditKeyDown}
                      aria-label={'Edit task ' + todo.text}
                    />
                  ) : (
                    <span className={'todo-text' + (todo.done ? ' done' : '')}>
                      {todo.text}
                    </span>
                  )}
                </div>
                <div className="item-actions">
                  <button
                    ref={(node) => {
                      if (node) editButtonRefs.current.set(todo.id, node);
                      else editButtonRefs.current.delete(todo.id);
                    }}
                    type="button"
                    className="ghost edit-task"
                    data-id={todo.id}
                    onClick={() => startEditing(todo)}
                    disabled={editingId === todo.id}
                    aria-label={'Edit ' + todo.text}
                  >
                    Edit
                  </button>
                  <button
                    type="button"
                    className="ghost remove-task"
                    onClick={() => removeTask(todo.id)}
                    aria-label={'Remove ' + todo.text}
                  >
                    Remove
                  </button>
                </div>
              </li>
            ))}
          </ul>
          {!visibleTodos.length && (
            <p className="empty">
              {todos.length ? 'No tasks in this filter.' : 'No tasks yet.'}
            </p>
          )}

          <div className="footer">
            <div className="filters" role="group" aria-label="Filter tasks">
              <button type="button" className="filter-button filter-all" aria-pressed={filter === 'all'} onClick={() => setFilter('all')}>All</button>
              <button type="button" className="filter-button filter-active" aria-pressed={filter === 'active'} onClick={() => setFilter('active')}>Active</button>
              <button type="button" className="filter-button filter-completed" aria-pressed={filter === 'completed'} onClick={() => setFilter('completed')}>Completed</button>
            </div>
            <div className="footer-row">
              <p id="items-left" className="items-left" role="status" aria-live="polite" aria-atomic="true">
                {remainingLabel}
              </p>
              <button type="button" className="ghost clear-completed" onClick={clearCompleted} disabled={!hasCompleted}>
                Clear completed
              </button>
            </div>
          </div>

          {pendingUndo && (
            <div className="undo-bar" role="status" aria-live="polite" aria-atomic="true">
              <span>Removed {pendingUndo.item.text}.</span>
              <button
                type="button"
                className="undo-button"
                onClick={undoRemoval}
                aria-label={'Undo removal of ' + pendingUndo.item.text}
              >
                Undo
              </button>
            </div>
          )}
          <p className="visually-hidden" aria-live="polite" aria-atomic="true">{liveMessage}</p>
        </div>
      </section>
    </main>
  );
}
